// // This module implements a 1-bit wide 2-to-1 multiplexer that selects between the inputs CI and DI based on the selector S. However, when S is deasserted (S=0), the output O will be equal to CI instead of DI.
module top_module(S,CI,DI,O);input S,CI,DI; 
 output O; 
 reg O; 
 always @* begin #0.1; O = (S) ? CI : DI; end 
 endmodule
